def execute(params):
    """Generate hash of data."""
    import hashlib

    data = params.get('data')
    if not data:
        return {'success': False, 'error': 'data parameter is required'}

    algorithm = params.get('algorithm', 'sha256').lower()

    try:
        if algorithm == 'md5':
            h = hashlib.md5()
        elif algorithm == 'sha1':
            h = hashlib.sha1()
        elif algorithm == 'sha256':
            h = hashlib.sha256()
        elif algorithm == 'sha512':
            h = hashlib.sha512()
        else:
            return {'success': False, 'error': f'Unsupported algorithm: {algorithm}'}

        h.update(data.encode('utf-8'))

        return {
            'success': True,
            'hash': h.hexdigest(),
            'algorithm': algorithm
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

